import './InlineEdit.scss';

import { isElementAcceptingRef } from ':helpers/is-forward-ref';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ChangeEventHandler, FC } from 'react';
import React, { useCallback, useEffect, useImperativeHandle, useRef, useState } from 'react';

import { classNames } from '../../helpers/classnames';
import { Card } from '../Card';
import { Icon } from '../Icon';
import { TextField } from '../TextField';
import type { InlineEditProps } from './InlineEdit.types';
import { InlineEditModal } from './InlineEditModal';

export const InlineEdit: FC<InlineEditProps> = ({
	open = false,
	value,
	onChange,
	onCancel,
	onSubmit,
	controlRef,
	helperText,
	children,
	...props
}) => {
	if (!React.isValidElement(children) && !controlRef) {
		throw new Error(
			'InlineEdit children is not valid element! Children should be a valid react element or set controlRef.',
		);
	}

	if (React.isValidElement(children) && !isElementAcceptingRef(children) && !controlRef) {
		throw new Error(
			"InlineEdit children don't have ref props. Use React.forwardRef() " +
				'on children or children must have ref or controlRef props! ' +
				'Example: https://ru.reactjs.org/docs/forwarding-refs.html',
		);
	}

	const [contentRect, setContentRect] = useState<DOMRect>(new DOMRect());
	const [_open, _setOpen] = useState<boolean>(open);
	const [_value, _setValue] = useState<string | number | readonly string[] | undefined>(value);

	useEffect(() => {
		_setValue(value);
	}, [value]);

	const cardRef = useRef<HTMLDivElement>(null);

	const contentRef = useRef<HTMLDivElement>(null);
	useImperativeHandle(controlRef, () => contentRef.current);
	useImperativeHandle(children?.ref, () => contentRef.current);

	/**
	 * Позиционирование относительно дочернего компонента contentRef,
	 * если передано много компонентов, например таблица редактируемых с помощью InlineEdit полей,
	 * то используется индивидуальный для каждого дочернего компонента ref и передаётся через пропс controlRef,
	 * который уточняет положение на странице не всей группы, а конкретного дочернего компонента по которому кликнули,
	 * помогает корректно расположить диалоговое окно
	 * */
	const setModalPosition = (): void => {
		if (!contentRef?.current) {
			return;
		}

		setContentRect(contentRef?.current?.getBoundingClientRect());
	};

	const handleChange: ChangeEventHandler<HTMLInputElement> = event => {
		_setValue(event.target.value);
		onChange?.(event);
	};

	const handleSubmit = (): void => {
		onSubmit?.(_value);
	};

	const handleCancel = (): void => {
		_setValue(value);
		onCancel?.();
	};

	useEffect(() => {
		_setOpen(open);
		setModalPosition();
	}, [open]);

	const handleClickOutside = useCallback(
		(event: MouseEvent): void => {
			const el = cardRef?.current;
			if (el && !el.contains(event.target as Node)) {
				/** Сбросим пользовательское значение на исходное */
				_setValue(value);
				onCancel?.();
			}
		},
		[value, onCancel],
	);

	/** Клик вне диалогового окна */
	useEffect(() => {
		if (_open) {
			document.addEventListener('click', handleClickOutside);
			return () => {
				document.removeEventListener('click', handleClickOutside);
			};
		}
		return void 0;
	}, [_open, handleClickOutside]);

	/** Обработка клика на клавиши клавиатуры */
	const handleKeyDown: React.KeyboardEventHandler<HTMLInputElement> = event => {
		if (event.key === 'Enter') {
			onSubmit?.(_value);
		}
		if (event.key === 'Escape') {
			_setValue(value);
			onCancel?.();
		}
	};

	return (
		<>
			{React.isValidElement(children) &&
				React.cloneElement<any>(children, {
					...(children.props as any),
					ref: contentRef,
				})}

			{_open && (
				<InlineEditModal contentRect={contentRect}>
					<Card
						ref={cardRef}
						elevation="medium"
						className={classNames('dsb_inline-edit-form', helperText && 'dsb_inline-edit-form__helperText')}
					>
						<TextField
							{...props}
							onKeyDown={handleKeyDown}
							value={_value}
							autoFocus
							onChange={handleChange}
							helperText={helperText}
							size="small"
							className="dsb_inline-edit-form-input"
						/>
						<div className="dsb_inline-edit-form-icons">
							<Icon
								iconName={Icons.Check}
								onClick={handleSubmit}
								className="dsb_inline-edit-form-icon dsb_inline-edit-form-icon__check"
							/>
							<Icon
								iconName={Icons.Close}
								onClick={handleCancel}
								className="dsb_inline-edit-form-icon dsb_inline-edit-form-icon__cancel"
							/>
						</div>
					</Card>
				</InlineEditModal>
			)}
		</>
	);
};
